import json
import logging
import os
import shlex
import subprocess
import sys
import time

import pika


logging.basicConfig(
    level=os.getenv("LOG_LEVEL", "INFO"),
    format="%(asctime)s %(levelname)s %(message)s",
)

RABBITMQ_URL = os.getenv("RABBITMQ_URL", "amqp://guest:guest@localhost:5672/%2F")
QUEUE_NAME = os.getenv("QUEUE_NAME", "jobs")
PREFETCH_COUNT = int(os.getenv("PREFETCH_COUNT", "1"))
RETRY_DELAY_SECONDS = int(os.getenv("RETRY_DELAY_SECONDS", "5"))


def execute_command(message_body: bytes) -> subprocess.CompletedProcess:
    try:
        payload = json.loads(message_body.decode("utf-8"))
        command = payload["command"]
    except Exception:
        text = message_body.decode("utf-8", errors="replace").strip()
        command = shlex.split(text)

    if isinstance(command, str):
        command = shlex.split(command)

    if not isinstance(command, (list, tuple)) or not command:
        raise ValueError("Invalid command payload")

    logging.info("Executing command: %s", command)
    return subprocess.run(
        command,
        capture_output=True,
        text=True,
        check=False,
        timeout=int(os.getenv("COMMAND_TIMEOUT", "3600")),
    )


def on_message(channel, method, properties, body):
    try:
        result = execute_command(body)
        logging.info("Command exited with code %s", result.returncode)

        if result.stdout:
            logging.info("stdout: %s", result.stdout.strip())
        if result.stderr:
            logging.warning("stderr: %s", result.stderr.strip())

        if result.returncode == 0:
            channel.basic_ack(delivery_tag=method.delivery_tag)
        else:
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except subprocess.TimeoutExpired as exc:
        logging.exception("Command timed out: %s", exc)
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
    except Exception as exc:
        logging.exception("Failed to process message: %s", exc)
        channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)


def main():
    params = pika.URLParameters(RABBITMQ_URL)

    while True:
        try:
            connection = pika.BlockingConnection(params)
            channel = connection.channel()
            channel.queue_declare(queue=QUEUE_NAME, durable=True)
            channel.basic_qos(prefetch_count=PREFETCH_COUNT)
            channel.basic_consume(queue=QUEUE_NAME, on_message_callback=on_message)

            logging.info("Consumer started. Waiting for messages on queue '%s'", QUEUE_NAME)
            channel.start_consuming()
        except KeyboardInterrupt:
            logging.info("Shutting down consumer")
            try:
                if "channel" in locals() and channel.is_open:
                    channel.stop_consuming()
            except Exception:
                pass
            try:
                if "connection" in locals() and connection.is_open:
                    connection.close()
            except Exception:
                pass
            sys.exit(0)
        except Exception as exc:
            logging.exception("Connection/consumer error: %s", exc)
            time.sleep(RETRY_DELAY_SECONDS)


